const all = $input.all().map(i => i.json);
const entries = all.slice(0, 50);
const now = new Date();
const twoHoursAgo = new Date(now - 2 * 60 * 60 * 1000);
const recent = all.filter(e => e.type === 'contraction' && new Date(e.logged_at) >= twoHoursAgo);
const totalCount = all.filter(e => e.type === 'contraction').length;

let stats = { total: totalCount, count_2h: recent.length, avg_gap_min: null, avg_intensity: null, intensity_label: null };

if (recent.length >= 2) {
  const times = recent.map(e => new Date(e.logged_at).getTime()).sort((a,b) => b - a);
  let gaps = [];
  for (let i = 0; i < times.length - 1; i++) gaps.push((times[i] - times[i+1]) / 60000);
  const avgGap = gaps.reduce((a,b) => a+b, 0) / gaps.length;
  stats.avg_gap_min = Math.round(avgGap * 10) / 10;

  const iMap = { mild: 1, moderate: 2, strong: 3, intense: 4 };
  const iLabels = ['mild', 'moderate', 'strong', 'intense'];
  const withI = recent.filter(e => e.intensity && iMap[e.intensity]);
  if (withI.length > 0) {
    const avgI = withI.reduce((s,e) => s + iMap[e.intensity], 0) / withI.length;
    stats.avg_intensity = Math.round(avgI * 10) / 10;
    stats.intensity_label = iLabels[Math.round(avgI) - 1] || 'unknown';
  }
}

return [{ json: { count: entries.length, stats, entries } }];
